Options:
  --config <path>   Path to mcp.json (default: ./mcp.json)

The config file uses the standard mcpServers format:
  {
    "mcpServers": {
      "my-server": {
        "command": "bun",
        "args": ["run", "server.js"],
        "env": { "API_KEY": "..." }
      },
      "remote-server": {
        "url": "https://example.com/mcp/",
        "headers": { "Authorization": "Bearer ..." }
      }
    }
  }`);
		if (command && command !== "--help" && command !== "help") {
			process.exit(1);
		}
		break;
}
