+
+	test("compiled cli responds to --help promptly", async () => {
+		const tempDir = await mkdtemp(join(tmpdir(), "sprout-cli-compiled-"));
+		tempDirs.push(tempDir);
+		const outfile = join(tempDir, "sprout-test");
